// Memanggil kembali memori internal n8n
const staticData = $getWorkflowStaticData('global');

const opsiJakarta = {
  timeZone: 'Asia/Jakarta',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: false
};

// Pengformat otomatis
const formatter = new Intl.DateTimeFormat('en-US', opsiJakarta);

function formatKeIso(ts) {
  const bagian = formatter.formatToParts(new Date(ts));
  const d = Object.fromEntries(bagian.map(b => [b.type, b.value]));
  // Menghasilkan format standar: YYYY-MM-DDTHH:mm:ss
  return `${d.year}-${d.month}-${d.day}T${d.hour}:${d.minute}:${d.second}`;
}

// 1. Mengambil waktu mulai dari memori.
const startTs = staticData.sleepStartTimestamp;
const endTs = new Date().getTime();

// 2. PROTEKSI DATA KETAT
// Jika tidak ada memori startTs (webhook mulai terlewat/gagal),
// kita HENTIKAN alur di sini agar tidak mengirim data sampah/halusinasi ke database.
if (!startTs) {
  return []; 
}

// 3. Menghitung selisih waktu menjadi menit
const sleepMinutes = Math.round((endTs - startTs) / 60000);

// 4. KATEGORISASI TIDUR CERDAS
let sleepType = "Tidur Utama";
if (sleepMinutes <= 180) { 
  // Jika durasi di bawah 3 jam, asumsikan ini tidur siang atau sesi lanjut tidur
  sleepType = "Tidur Siang / Ekstra";
}

// 5. Menghapus memori agar bersih untuk sesi tidur berikutnya (di hari yang sama)
staticData.sleepStartTimestamp = undefined;

// 6. Menyiapkan paket data kaya untuk database
return [{
  json: {
    // Format YYYY-MM-DD yang aman untuk zona waktu Jakarta
    logged_date: new Date(endTs).toLocaleString('en-CA', {timeZone: 'Asia/Jakarta'}).split(',')[0],
    sleep_duration_minutes: sleepMinutes,
    sleep_type: sleepType,
    session_start: formatKeIso(startTs),
    session_end: formatKeIso(endTs)
  }
}];

const events = $input.all();
let scheduleText = "JADWAL KULIAH AFIN HARI INI:\n";

if (events.length === 0 || !events[0].json.summary) {
  scheduleText += "- TIDAK ADA JADWAL KULIAH (Hari ini kosong!).\n";
} else {
  for (const item of events) {
    const ev = item.json;

    // Memaksa mesin JavaScript n8n merender waktu dalam zona Asia/Jakarta secara absolut
    const startHour = new Date(ev.start.dateTime).toLocaleTimeString('id-ID', {
      timeZone: 'Asia/Jakarta', 
      hour: '2-digit', 
      minute: '2-digit'
    }).replace('.', ':'); // Mengubah titik menjadi titik dua (contoh: 13.10 jadi 13:10)

    const endHour = new Date(ev.end.dateTime).toLocaleTimeString('id-ID', {
      timeZone: 'Asia/Jakarta', 
      hour: '2-digit', 
      minute: '2-digit'
    }).replace('.', ':');

    scheduleText += `- ${ev.summary} (${startHour} - ${endHour}) di ${ev.location || 'Kelas'}\n`;
  }
}

return [{ json: { formatted_schedule: scheduleText } }];

